import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import CryptoMLMIndex from "@screens/crypto-mlm-software-development";
import { useLocation } from "@reach/router";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";
import Layout_v2 from "@components/layout_v2";

const CryptoMLMPage = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Crypto MLM Software Development Company", link: "" },
  ];
  const { data } = props;
  const location = useLocation();
  const fileUrl =
    data?.cryptoMlmImg?.childImageSharp?.gatsbyImageData?.images?.fallback?.src;
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "A crypto MLM software development firm develops blockchain-based applications, which are secure, to handle the members, commissions, and crypto rewards.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1453",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What is crypto MLM software development?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Crypto MLM software development is an act of creating blockchain-based multi-level marketing systems where cryptocurrencies are used to register members, commissions, awards, and undertake transactions.",
            },
          },
          {
            "@type": "Question",
            name: "What is crypto MLM software development?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "The development of crypto MLM software is the development of blockchain-based multi-level marketing applications that require the use of cryptocurrencies to make payments, commissions, referrals, and distribute rewards using smart contracts.",
            },
          },
          {
            "@type": "Question",
            name: "How much does it cost to build a crypto MLM platform?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "The price of a crypto MLM platform depends on the features, security, and personalisation, with prices between 5,000 to 50,000-plus as a general range of the entry-level to advanced systems.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <CryptoMLMIndex db={db} />
    </Layout_v2>
  );
};

export default CryptoMLMPage;

export const queryData = graphql`
  query MyQuery {
    cryptoMlmImg: file(relativePath: { eq: "crypto-mlm-development.png" }) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(
      filter: { slug: { eq: "cryptocurrency-mlm-software-development" } }
    ) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
